// グローバル _Bool の初期化/代入/複合代入が 0/1 に正規化されないバグ。
// global_var_t が _Bool かどうかを追跡しておらず (is_bool 未設定)、ND_GVAR 参照にも
// 伝播していなかったため、初期化子・代入・複合代入のいずれも正規化されなかった
// (`_Bool b=5;` がグローバルだと 5 のまま)。ローカル _Bool は正常だった。
// C11 6.3.1.2: _Bool への変換/代入は 0/1 に正規化される。
// 修正前: exit=他の値 (5, 7, 11 等)
// 期待: exit=42
_Bool a = 5;     // 初期化 -> 1
_Bool b = 0;
_Bool c = 1;
int main(void) {
    b = 7;        // 通常代入 -> 1
    c += 10;      // 複合代入 -> 1
    return (a == 1 && b == 1 && c == 1) ? 42 : 0;
}
